println("--- Running Theorem: Wildcard Collapse ---")                               # ║ ║                              ║
println("Test 1: Specific Coordinate (Manna)")                                      # ║ ║                              ║
println(WildcardCollapse.calculate_friction(WildcardCollapse.Query(false, 100.0)))  # ║ ║                              ║
println("Test 2: Unbounded Wildcard (**/*)")                                        # ║ ║                              ║
println(WildcardCollapse.calculate_friction(WildcardCollapse.Query(true, 0.0)))     # ║ ║                              ║
